CREATE TABLE IF NOT EXISTS privacy_appeals(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id text NOT NULL,case_id uuid NOT NULL,reason text NOT NULL,status text NOT NULL DEFAULT 'received',received_at timestamptz NOT NULL,due_at timestamptz NOT NULL,reviewer text NOT NULL DEFAULT '',decision_reason text NOT NULL DEFAULT '',decided_at timestamptz,metadata jsonb NOT NULL DEFAULT '{}'::jsonb,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS privacy_regulator_inquiries(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id text NOT NULL,authority text NOT NULL,reference text NOT NULL,subject text NOT NULL DEFAULT '',status text NOT NULL DEFAULT 'received',received_at timestamptz NOT NULL,due_at timestamptz NOT NULL,owner text NOT NULL DEFAULT '',response text NOT NULL DEFAULT '',submitted_at timestamptz,closed_at timestamptz,metadata jsonb NOT NULL DEFAULT '{}'::jsonb,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now());
CREATE INDEX IF NOT EXISTS idx_privacy_appeals_due ON privacy_appeals(tenant_id,status,due_at); CREATE INDEX IF NOT EXISTS idx_privacy_inquiries_due ON privacy_regulator_inquiries(tenant_id,status,due_at);
